option.value:
/* Placeholder for global styles. */

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "Segoe UI", system-ui, sans-serif;
  background: #f5f6f8;
  color: #1f2933;
}

.app {
  min-height: 100vh;
}

.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 2rem;
  background: #111827;
  color: #fff;
}

.navbar a {
  color: #e5e7eb;
  margin-right: 1rem;
  text-decoration: none;
}

.navbar a.active {
  color: #fff;
  font-weight: 600;
}

.navbar-links {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.link-button {
  background: none;
  border: none;
  color: #e5e7eb;
  cursor: pointer;
}

.app-content {
  padding: 2rem;
}

.page {
  max-width: 960px;
  margin: 0 auto;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.hero {
  background: #fff;
  padding: 3rem;
  border-radius: 16px;
  text-align: center;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.08);
}

.hero-actions {
  margin-top: 2rem;
  display: flex;
  justify-content: center;
  gap: 1rem;
}

.card {
  background: #fff;
  padding: 1.5rem;
  border-radius: 12px;
  box-shadow: 0 6px 18px rgba(0, 0, 0, 0.08);
}

.form {
  display: grid;
  gap: 1rem;
}

input,
select,
textarea {
  width: 100%;
  padding: 0.5rem;
  border: 1px solid #d1d5db;
  border-radius: 8px;
}

.primary-button,
.secondary-button,
.danger-button {
  padding: 0.6rem 1.2rem;
  border-radius: 8px;
  border: none;
  cursor: pointer;
}

.primary-button {
  background: #2563eb;
  color: #fff;
}

.secondary-button {
  background: #e5e7eb;
}

.danger-button {
  background: #dc2626;
  color: #fff;
}

.error {
  color: #b91c1c;
}

.message {
  color: #1d4ed8;
}

.empty {
  color: #6b7280;
}

.small {
  font-size: 0.85rem;
  color: #6b7280;
}

.grid-list {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
  margin-top: 1.5rem;
}

.puzzle-card {
  text-align: left;
  border: none;
  cursor: pointer;
}

.solver-layout {
  display: grid;
  grid-template-columns: 1fr 280px;
  gap: 2rem;
}

.creator-layout {
  display: grid;
  grid-template-columns: 1fr 280px;
  gap: 2rem;
}

@media (max-width: 768px) {
  .solver-layout {
    grid-template-columns: 1fr;
  }

  .creator-layout {
    grid-template-columns: 1fr;
  }
}

.creator-grid {
  display: grid;
  gap: 4px;
  background: #111827;
  padding: 4px;
  border-radius: 12px;
}

.creator-cell {
  position: relative;
  background: #fff;
  border: none;
  width: 100%;
  aspect-ratio: 1 / 1;
  padding: 0;
}

.creator-cell.selected {
  background: #dbeafe;
}

.cage-sum {
  position: absolute;
  top: 2px;
  left: 4px;
  font-size: 0.65rem;
  color: #111827;
  z-index: 2;
}

.cage-sum-button {
  position: absolute;
  top: 2px;
  left: 4px;
  font-size: 0.65rem;
  padding: 0;
  border: none;
  background: transparent;
  color: #111827;
  cursor: pointer;
}

.cage-delete {
  position: absolute;
  top: 2px;
  right: 4px;
  font-size: 0.7rem;
  padding: 0 4px;
  border: none;
  background: #fee2e2;
  color: #b91c1c;
  border-radius: 6px;
  cursor: pointer;
}

.grid-cell-wrapper {
  position: relative;
  background: #fff;
}

.grid-cell-wrapper.hinted {
  background: #dcfce7;
}

.grid-cell-wrapper .grid-cell {
  background: transparent;
}

.grid,
.creator-grid {
  width: 100%;
  max-width: 540px;
}

.grid-row {
  display: grid;
  grid-template-columns: repeat(9, minmax(0, 1fr));
  gap: 4px;
}

.grid-cell,
.creator-cell {
  width: 100%;
  height: 100%;
  aspect-ratio: 1 / 1;
  font-size: clamp(0.75rem, 1.8vw, 1rem);
}

.checkbox-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0.5rem 0 1rem;
  color: var(--ink-2);
  font-size: 0.9rem;
}

.checkbox-row input {
  width: auto;
}

.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(15, 23, 42, 0.6);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 2000;
}

.modal {
  position: relative;
  max-width: 900px;
  width: min(92vw, 900px);
  max-height: 90vh;
  overflow: auto;
}

