.modal-images {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
  margin: 1.5rem 0;
}

.modal-images figure {
  margin: 0;
}

.modal-images img {
  width: 100%;
  max-height: 220px;
  object-fit: contain;
  border-radius: 8px;
}

@media (max-width: 700px) {
  .modal-images {
    grid-template-columns: 1fr;
  }
}
